  ('dietitian-moex-08215', 'dietitian', 'dietitian-moex-099-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '有關生長的敘述，下列何者正確？', '["第一型類胰島素生長因子（IGF-I）可抑制軟骨細胞的增生", "生長激素（growth hormone）通常在白天大量分泌", "兒童時期若營養不良，會抑制第一型類胰島素生長因子（IGF-I）的生成", "胰島素不影響蛋白質合成與生長，因此與生長無關"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:49+00:00", "source_pdf_sha1": "0fff3c4ec8eb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "108", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
