  ('dietitian-moex-08218', 'dietitian', 'dietitian-moex-099-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '某一物質（X）血中濃度為4 mg/L，尿液中X物質濃度為300 mg/L，尿液收集量為0.2 L，尿液收集時間 為2小時（h），則該物質X的清除率（clearance）為：', '["7.5 L/h", "15 mg/h", "15 L/h", "75 mg/h"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:49+00:00", "source_pdf_sha1": "0fff3c4ec8eb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "108", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08219', 'dietitian', 'dietitian-moex-099-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '有關鐵在人體內吸收之敘述，下列何者錯誤？', '["亞鐵離子（Fe+2）較鐵離子（Fe+3）容易被腸道吸收", "胃酸能幫助鐵的吸收", "鐵在小腸細胞內，會與儲鐵蛋白原（apoferritin）形成儲鐵蛋白（ferritin）", "鐵離子在血中主要是以游離的狀態運送"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:49+00:00", "source_pdf_sha1": "0fff3c4ec8eb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "108", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
